import javafx.application.Application;
import javafx.scene.Scene;
import javafx.scene.control.Label;
import javafx.scene.layout.StackPane;
import javafx.stage.Stage;

public class FirstJavaFXWindow extends Application {

    @Override
    public void start(Stage primaryStage) {
        // Create a Label (text node)
        Label label = new Label("Hello, JavaFX!");

        // Create a layout container
        StackPane root = new StackPane();
        root.getChildren().add(label);

        // Create a Scene
        Scene scene = new Scene(root, 400, 300);

        // Set up the Stage
        primaryStage.setTitle("My First JavaFX Window");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}

// Alternative: Using VBox for vertical layout
class SecondJavaFXWindow extends Application {
    @Override
    public void start(Stage primaryStage) {
        // Create multiple controls
        Label label1 = new Label("Welcome to JavaFX!");
        Label label2 = new Label("This is a second label.");

        // VBox arranges nodes vertically
        javafx.scene.layout.VBox root = new javafx.scene.layout.VBox(10);
        root.getChildren().addAll(label1, label2);

        Scene scene = new Scene(root, 400, 300);

        primaryStage.setTitle("Second JavaFX Window");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}

